+void GVNSink::analyzeInitialPHIs(BasicBlock *BB, ModelledPHISet &NeededPHIs,
+                                 SmallPtrSetImpl<Value *> &PHIContents) {
+  for (auto &I : *BB) {
+    auto *PN = dyn_cast<PHINode>(&I);
+    if (!PN)
+      break;
+    NeededPHIs.insert({PN, RPOTOrder});
+    for (auto V : PN->incoming_values())
+      PHIContents.insert(V);
+  }
+}
