+bool GVNSink::shouldAvoidSinkingInstruction(Instruction *I) {
+  if (auto *CI = dyn_cast<CallInst>(I)) \
+    if (CI->isInlineAsm()) \
+      return true;
+  if (auto *CI = dyn_cast<CallInst>(I)) 
+    if (CI->isInlineAsm()) 
+      return true;
+  // These instructions may change or break semantics if moved.
+  if (isa<PHINode>(I) || I->isEHPad() || isa<AllocaInst>(I) ||
+      I->getType()->isTokenTy())
+    return true;
+  return false;
+}
